189	def FuseForallOp : Op<Transform_Dialect, "iree.fuse_forall",
190	    [FunctionalStyleTransformOpTrait,
191	     DeclareOpInterfaceMethods<MemoryEffectsOpInterface>,
192	     DeclareOpInterfaceMethods<TransformOpInterface>,
193	     ReportTrackingListenerFailuresOpTrait]> {
194	  let description = [{
195	    Fuses a producer-consumer pair of scf.forall ops that share the same
196	    iterator mapping types and trip counts. An allocation is created to
197	    bridge the `parallel.insert_slice` of the producer with the per-thread
198	    `extract_slice` of the consumer. If specified, uses |address_space| for
199	    the intermediate allocation.
200	
201	    The mapping attributes of both the producer and consumer `scf.forall` ops
202	    must be in a relative descending order, for example:
203	     [#gpu.thread<z>, #gpu.thread<y>, #gpu.thread<x>]
204	    or
205	     [#gpu.thread<linear_dim_1>, #gpu.thread<linear_dim_0>]
206	
207	    NOTE: This pattern implicitly REQUIRES that the resulting scf.forall
208	    is capable of synchronizing all threads at the point of fusion (i.e.
209	    inserting a barrier). This invalidates certain kinds of lowerings of
210	    scf.forall ops such as lowering it to loops.
211	
212	    #### Return modes
213	    Emits a definite failure if either the producer or consumer are not
214	    scf.forall ops.
215	  }];
216	
217	  let arguments = (
218	      ins TransformHandleTypeInterface:$producer,
219	          TransformHandleTypeInterface:$consumer,
220	          OptionalAttr<AnyAttr>:$address_space
221	  );
222	  let results = (outs TransformHandleTypeInterface:$result);
223	
224	  let assemblyFormat = [{
225	    $producer `into` $consumer attr-dict
226	    `:` functional-type(operands, results)
227	  }];
228	  let cppNamespace = "mlir::iree_compiler::IREE::transform_dialect";
229	}
