302	def ForallToWorkgroupOp : Op<Transform_Dialect,
303	    "iree.forall_to_workgroup",
304	    [DeclareOpInterfaceMethods<MemoryEffectsOpInterface>,
305	     TransformEachOpTrait,
306	     TransformOpInterface,
307	     ReportTrackingListenerFailuresOpTrait]> {
308	  let description = [{
309	    Target the whole hal.executable_variant op and rewrite the unique topLevel
310	    scf.forall to distributed workgroup_id and workgroup_count.
311	
312	    The mapping of threads to workgroup_id is currently one-to-one and in order.
313	    Only **bufferized** scf.forall are currently supported.
314	    Only scf.forall distributed to **at most 3 dimensions** are currently
315	    supported.
316	
317	    Return modes:
318	    =============
319	    This operation ignores non-Func ops and drops them in the return.
320	
321	    If no unique scf.forall topLevel operation is found, then the
322	    transform definitely fails.
323	    If the unique topLevel scf.forall has results (i.e. tensors), then
324	    the transform definitely fails.
325	
326	    If the unique topLevel scf.forall maps to a dynamic number of
327	    threads, then the transform definitely fails. This is a temporary
328	    limitation until the backward slice computing scf.forall.num_threads
329	    can be extracted into the hal::executable_export workgroup_count region.
330	    This region may require arbitrary computations and cannot magically match
331	    what the `stream.cmd.dispatch` has already imposed on us at a distance.
332	    For now we must specify the number of values properly when applying the
333	    topLevel tile_using_forall.
334	
335	    If the unique topLevel scf.forall operation contained within the
336	    FuncOp referred to by the `target` transform handle lowers to workgroup
337	    properly, the transform succeeds.
338	
339	    Otherwise the transform definitely fails.
340	
341	    This transform does not consume its input handle and produces no result.
342	  }];
343	
344	  let arguments = (ins TransformHandleTypeInterface:$target);
345	  let results = (outs);
346	
347	  let assemblyFormat = "$target attr-dict `:` functional-type($target, results)";
