537	def ShareForallOperandsOp : Op<
538	    Transform_Dialect, "iree.share_forall_operands", [
539	      FunctionalStyleTransformOpTrait,
540	      MemoryEffectsOpInterface,
541	      TransformEachOpTrait,
542	      TransformOpInterface,
543	      ReportTrackingListenerFailuresOpTrait]> {
544	  let description = [{
545	    Target a single scf.forall op and shares all uses of the specified
546	    `share_operands` operand indices.
547	
548	    Sharing can be thought of as the inverse of traditional privatization.
549	    Privatization consists in determining that a part of memory is only accessed
550	    by a single thread to and subsequently slicing out that part into a
551	    thread_private storage that has smaller footprint, better locality and better
552	    alignment properties.
553	    In the case of scf.forall on tensors, tensor values are immutable
554	    and the same tensor value may be passed as `shared_outs` and also captured
555	    for internal uses.
556	    Due to the immutability property, the whole tensor values are private by
557	    construction and result in alloc + copy of the whole tensor on every thread
558	    to maintain the original SSA value after bufferizing.
559	
560	    An analysis similar to privatization is needed to ensure that only a private
561	    slice is needed and that the whole tensor can be shared.
562	    This transformation amounts to injecting the result of such an analysis as
563	    static information in the program.
564	    The transformation checks that the values captured are `tensor.extract_slice`
565	    with a matching `tensor.parallel_insert_slice`, to approximate the lack of
566	    a cross-thread dependence analysis.
567	    However this can still be unsafe wrt parallelism so use carefully!
568	
569	    Sharing consists in rewriting all uses of the operands passed as
570	    `shared_outs` that are also captured wihtin the `scf.forall` region
571	    into the matching `shared_outs` bbarg.
572	
573	    Only those operands whose indices are specified in `share_operands` are
574	    shared. An empty `share_operands` specification considers all operands to
575	    be shared.
576	
577	    #### Return modes
578	
579	    If any of the `share_operands` indices overflow, a definite error is produced.
580	
581	    If a `share_operands` fails a sharing precondition, it is ignored.
582	    In the future, we should emit a notification.
583	
584	    This transform consumes the target handle and produces a result handle to
585	    the modified `scf.forall` op.
586	  }];
587	
588	  let arguments = (
589	      ins TransformHandleTypeInterface:$forall_op,
590	          DefaultValuedOptionalAttr<DenseI64ArrayAttr, "{}">:$share_operands
591	  );
592	  let results = (outs TransformHandleTypeInterface:$result);
593	
594	  let cppNamespace = "mlir::iree_compiler::IREE::transform_dialect";
595	
596	  let assemblyFormat = [{
597	    $forall_op (`share_operands` `=` $share_operands^ )? attr-dict
598	      `:` functional-type(operands, results)
599	  }];
600	
601	  let extraClassDeclaration = [{
602	    ::mlir::DiagnosedSilenceableFailure applyToOne(
603	        ::mlir::transform::TransformRewriter &rewriter,
604	        ::mlir::scf::ForallOp forallOp,
605	        ::mlir::transform::ApplyToEachResultList &results,
606	        ::mlir::transform::TransformState &state);
607	  }];
608	}
